   482→
   483→// Helper function to convert degrees to sign and degree
   484→function degreesToSignAndDegree(degrees: number): {
   485→  sign: string;
   486→  degree: number;
   487→} {
   488→  const signs = [
   489→    "Aries",
   490→    "Taurus",
   491→    "Gemini",
   492→    "Cancer",
   493→    "Leo",
   494→    "Virgo",
   495→    "Libra",
   496→    "Scorpio",
   497→    "Sagittarius",
   498→    "Capricorn",
   499→    "Aquarius",
   500→    "Pisces",
   501→  ];
   502→
   503→  const normalizedDegrees = ((degrees % 360) + 360) % 360;
   504→  const signIndex = Math.floor(normalizedDegrees / 30);
   505→  const degree = normalizedDegrees % 30;
   506→
   507→  return {
   508→    sign: signs[signIndex],
   509→    degree: Math.round(degree * 100) / 100,
   510→  };
   511→}
   512→
   513→// Helper function to determine house for a planet
   514→function getPlanetHouse(planetDegrees: number, cusps: number[]): number {
   515→  const normalizedPlanet = ((planetDegrees % 360) + 360) % 360;
   516→
   517→  for (let i = 0; i < cusps.length; i++) {
   518→    const currentCusp = ((cusps[i] % 360) + 360) % 360;
   519→    const nextCusp = ((cusps[(i + 1) % cusps.length] % 360) + 360) % 360;
   520→
   521→    if (nextCusp > currentCusp) {
   522→      if (normalizedPlanet >= currentCusp && normalizedPlanet < nextCusp) {
   523→        return i + 1;
   524→      }
   525→    } else {
   526→      if (normalizedPlanet >= currentCusp || normalizedPlanet < nextCusp) {
   527→        return i + 1;
   528→      }
   529→    }
   530→  }
   531→
   532→  return 1; // fallback
   533→}
